mapper.update:
UPDATE FWK_SQL_CONF
DB_NAME = #{dto.dbName, jdbcType=VARCHAR}, DB_DESC = #{dto.dbDesc, jdbcType=VARCHAR}, CONNECTION_URL = #{dto.connectionUrl, jdbcType=VARCHAR}, DRIVER_CLASS = #{dto.driverClass, jdbcType=VARCHAR}, DB_USER_ID = #{dto.dbUserId, jdbcType=VARCHAR},
DB_PASSWORD = #{dto.dbPassword, jdbcType=VARCHAR},
JNDI_YN = #{dto.jndiYn, jdbcType=VARCHAR}, JNDI_ID = #{dto.jndiId, jdbcType=VARCHAR}, JNDI_PROVIDER_URL = #{dto.jndiProviderUrl, jdbcType=VARCHAR}, JNDI_CONTEXT_FACTORY = #{dto.jndiContextFactory, jdbcType=VARCHAR}, LAST_UPDATE_DTIME = #{lastUpdateDtime}, LAST_UPDATE_USER_ID = #{lastUpdateUserId}
WHERE DB_ID = #{dbId}

mapper.select:
SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT TRIM(d.DB_ID) AS dbId, TRIM(d.DB_NAME) AS dbName, TRIM(d.DB_DESC) AS dbDesc, TRIM(d.CONNECTION_URL) AS connectionUrl, TRIM(d.DRIVER_CLASS) AS driverClass, TRIM(d.DB_USER_ID) AS dbUserId, d.DB_PASSWORD AS dbPassword, d.JNDI_YN AS jndiYn, TRIM(d.JNDI_ID) AS jndiId, TRIM(d.JNDI_PROVIDER_URL) AS jndiProviderUrl, TRIM(d.JNDI_CONTEXT_FACTORY) AS jndiContextFactory, d.LAST_UPDATE_DTIME AS lastUpdateDtime, TRIM(d.LAST_UPDATE_USER_ID) AS lastUpdateUserId FROM FWK_SQL_CONF d
ORDER BY
d.DB_ID d.DB_NAME d.DB_USER_ID d.JNDI_YN d.LAST_UPDATE_DTIME d.DB_ID
ASC DESC ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
